function pageAllowed(page){return (PAGE_ACCESS[currentRole()]||['dashboard']).includes(page);}

function isoOffset(minutes){ return new Date(Date.now()+minutes*60000).toISOString(); }
function dateOffset(days,hour=9,minute=0){ const d=new Date();d.setDate(d.getDate()+days);d.setHours(hour,minute,0,0);return d.toISOString(); }
function auditEvent(actorId,action,detail,category='general'){return {id:Core.uid('audit'),at:new Date().toISOString(),actorId,action,detail,category};}

