function loadState(){try{const raw=localStorage.getItem(STORAGE_KEY);if(raw){const parsed=JSON.parse(raw);if(parsed.build==='MIND-2.0.0')return parsed;}}catch(e){console.warn('Demo storage unavailable',e);}return createInitialState();}
let state=loadState();
const ui={filter:'all',query:'',searchTimer:null};
function saveState(){try{localStorage.setItem(STORAGE_KEY,JSON.stringify(state));}catch(e){console.warn('Could not save demo state',e);}}
function logAction(action,detail,category='general',actorId=null){state.audit.unshift(auditEvent(actorId||state.currentUserId,action,detail,category));saveState();}
function esc(value=''){return String(value??'').replace(/[&<>'"]/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;',"'":'&#39;','"':'&quot;'}[c]));}
function fmtDate(value,withTime=true){if(!value)return 'Not recorded';const d=new Date(value);if(Number.isNaN(d.getTime()))return 'Invalid date';return new Intl.DateTimeFormat('en-AU',withTime?{day:'2-digit',month:'short',year:'numeric',hour:'2-digit',minute:'2-digit'}:{day:'2-digit',month:'short',year:'numeric'}).format(d);}
function fmtTime(value){return value?new Intl.DateTimeFormat('en-AU',{hour:'2-digit',minute:'2-digit'}).format(new Date(value)):'—';}
function relativeDue(value){const diff=new Date(value).getTime()-Date.now();const mins=Math.round(Math.abs(diff)/60000);if(diff<0)return `${mins} min overdue`;if(mins<60)return `due in ${mins} min`;return `due in ${Math.round(mins/60)} hr`;}
function staffById(id){return state.staff.find(x=>x.id===id);}
function clientById(id){return state.clients.find(x=>x.id===id);}
function obligationById(id){return state.obligations.find(x=>x.id===id);}
function currentRole(){return state.role||'director';}
function readOnly(){return currentRole()==='reviewer';}
function allowed(action){return Core.allowedForRole(action,currentRole());}
function levelPill(level,label=null){return `<span class="status-pill ${esc(level)}">${esc(label||level)}</span>`;}
function avatar(staff,level='blue'){return `<span class="avatar ${level}">${esc(staff?.initials||'—')}</span>`;}
function evidenceChips(required=[],evidence=[]){const have=new Set(evidence.map(e=>typeof e==='string'?e:e.type));return `<div class="evidence-list">${required.map(x=>`<span class="evidence-chip ${have.has(x)?'':'missing'}">${have.has(x)?'✓':'○'} ${esc(x.replaceAll('_',' '))}</span>`).join('')}</div>`;}
function progress(stage){return `<div class="progress-steps">${Core.WORKFLOW.map(s=>`<span class="progress-step ${Core.WORKFLOW.indexOf(s)<Core.WORKFLOW.indexOf(stage)?'done':s===stage?'current':''}">${esc(s.replaceAll('_',' '))}</span>`).join('')}</div>`;}
function toast(message){const el=document.getElementById('toast');el.textContent=message;el.classList.add('show');clearTimeout(el._t);el._t=setTimeout(()=>el.classList.remove('show'),2500);}
function updateClock(){document.getElementById('clock').innerHTML=new Intl.DateTimeFormat('en-AU',{weekday:'short',day:'2-digit',month:'short',year:'numeric'}).format(new Date())+'<br>'+new Intl.DateTimeFormat('en-AU',{hour:'2-digit',minute:'2-digit',second:'2-digit'}).format(new Date());}
function metric(value,label,detail='',tone=''){return `<div class="metric ${tone}"><strong>${esc(value)}</strong><span>${esc(label)}</span><small>${esc(detail)}</small></div>`;}
function sectionHeading(title,subtitle,actions=''){return `<div class="section-heading"><div><h2>${esc(title)}</h2><p>${esc(subtitle)}</p></div><div class="section-actions">${actions}</div></div>`;}
function card(title,subtitle,content,actions=''){return `<section class="card"><div class="card-header"><div><h2>${esc(title)}</h2>${subtitle?`<p>${esc(subtitle)}</p>`:''}</div><div class="card-actions">${actions}</div></div>${content}</section>`;}
function button(label,action,extra='',cls='btn small'){return `<button class="${cls}" type="button" data-action="${esc(action)}" ${extra}>${esc(label)}</button>`;}
function detailList(items){return `<dl class="detail-list">${items.map(([a,b])=>`<dt>${esc(a)}</dt><dd>${b}</dd>`).join('')}</dl>`;}

function navCount(page){
  if(page==='reception')return state.messages.filter(m=>m.status!=='closed').length;
  if(page==='obligations')return state.obligations.filter(o=>o.status!=='closed').length;
  if(page==='safety')return state.incidents.filter(i=>i.status!=='closed').length+state.obligations.filter(o=>o.category==='safety'&&o.status!=='closed').length;
  if(page==='continuity')return state.clients.filter(c=>Core.continuityState(c,state.obligations)!=='green').length;
  if(page==='supervision')return state.supervision.filter(s=>s.status!=='complete').length;
  if(page==='compliance')return state.whsHazards.filter(h=>h.status!=='closed'&&Core.rank(h.residualLevel)>=2).length+state.insurance.filter(i=>i.required&&i.status!=='current').length;
  return 0;
}
function renderNav(){document.getElementById('mainNav').innerHTML=NAV_ITEMS.filter(([id])=>pageAllowed(id)).map(([id,icon,label])=>{const count=navCount(id);return `<button class="nav-button ${state.activePage===id?'active':''}" type="button" data-nav="${id}"><span class="nav-icon">${icon}</span><span>${esc(label)}</span>${count?`<span class="nav-count">${count}</span>`:''}</button>`;}).join('');}
function updateHeader(){const meta=PAGE_META[state.activePage]||PAGE_META.dashboard;document.getElementById('pageTitle').textContent=meta[0];document.getElementById('pageSubtitle').textContent=meta[1];document.getElementById('roleSelect').value=currentRole();const boundary=document.getElementById('roleBoundary');boundary.textContent=ROLE_BOUNDARIES[currentRole()];boundary.classList.add('show');document.getElementById('notificationCount').textContent=state.obligations.filter(o=>o.status!=='closed'&&Core.rank(o.level)>=2).length;}
function render(){if(!pageAllowed(state.activePage))state.activePage='dashboard';renderNav();updateHeader();const renders={dashboard:renderDashboard,day:renderDay,staff:renderStaff,supervision:renderSupervision,continuity:renderContinuity,reception:renderReception,referrals:renderReferrals,obligations:renderObligations,safety:renderSafety,checks:renderChecks,compliance:renderCompliance,reports:renderReports,governance:renderGovernance};document.getElementById('page').innerHTML=(renders[state.activePage]||renderDashboard)();document.getElementById('page').focus({preventScroll:true});saveState();}

function practiceStateHero(){const ps=Core.calculatePracticeState(state);return `<div class="practice-state ${ps.level}"><div class="state-eyebrow">Psychology practice operational state</div><h2>${esc(ps.level.toUpperCase())}</h2><p>${esc(ps.reason)}</p><div class="state-actions">${button('View urgent queue','urgent-queue','', 'btn small')}${button('Open Immediate Safety Concern','immediate-concern','', 'btn small')}${button('Print current view','print','', 'btn small')}</div></div>`;}
function demoControls(){return `<div class="demo-controls"><h3>Official demo controls</h3><p>Use fictional scenarios to show how GENEVIEVE assigns ownership and preserves evidence.</p><div class="demo-control-grid"><button class="btn small danger" data-scenario="staff_absence">Staff absence</button><button class="btn small danger" data-scenario="distressed_call">Distressed call</button><button class="btn small secondary" data-scenario="provisional_gap">Supervision gap</button><button class="btn small secondary" data-scenario="workplace_incident">WHS incident</button></div></div>`;}
function obligationRows(items,limit=8){const list=items.slice(0,limit);if(!list.length)return '<div class="empty-state"><div class="empty-icon">✓</div><strong>No matching obligations</strong><span>Nothing is hidden in this fictional queue.</span></div>';return `<div class="list">${list.map(o=>{const owner=staffById(o.ownerId);return `<div class="list-row">${levelPill(o.level)}<div class="row-main"><strong>${esc(o.title)}</strong><small>${owner?`Owner: ${owner.name}`:'No accepted owner'} · ${relativeDue(o.dueAt)} · ${esc(o.stage.replaceAll('_',' '))}</small>${evidenceChips(o.requiredEvidence,o.evidence)}</div><div class="row-actions">${button('Open','open-obligation',`data-id="${o.id}"`,'btn small secondary')}${!readOnly()?button('Escalate','escalate-obligation',`data-id="${o.id}"`,'btn small danger'):''}</div></div>`;}).join('')}</div>`;}

function renderDashboard(){
  const ps=Core.calculatePracticeState(state),open=state.obligations.filter(o=>o.status!=='closed'),urgent=open.filter(o=>Core.rank(o.level)>=3),overdue=open.filter(o=>Core.dueState(o.dueAt)==='overdue');
  const gaps=state.clients.filter(c=>Core.continuityState(c,state.obligations)!=='green');
  const supervisionDue=state.supervision.filter(s=>s.status!=='complete');
  const checkOpen=state.checks.reduce((n,g)=>n+g.items.filter(i=>i.required&&!i.done).length,0);
  const banners=`<div class="banner-row"><div class="banner-card red"><strong>${urgent.length} urgent responsibilities</strong><span>Must have an acknowledged human owner</span></div><div class="banner-card amber"><strong>${overdue.length} overdue actions</strong><span>Evidence and outcome still required</span></div><div class="banner-card blue"><strong>${supervisionDue.length} supervision records</strong><span>Scheduled, planned or overdue</span></div><div class="banner-card green"><strong>${state.staff.filter(s=>s.status==='on_site'||s.status==='remote').length} staff available</strong><span>Coverage and workload visible</span></div></div>`;
  const staffList=state.staff.map(s=>`<div class="list-row">${avatar(s,s.status==='leave'?'amber':s.breakStatus==='overdue'?'red':'green')}<div class="row-main"><strong>${esc(s.name)} — ${esc(s.role)}</strong><small>${esc(s.status.replaceAll('_',' '))} · ${s.sessions}/${s.maxSessions||'—'} sessions · break ${esc(s.breakStatus.replaceAll('_',' '))}</small></div>${levelPill(s.status==='leave'?'amber':s.breakStatus==='overdue'?'red':s.piiStatus==='review_due'?'amber':'green',s.piiStatus==='review_due'?'insurance review':s.status)}</div>`).join('');
  const dashboardActions=`${button('New task','new-obligation')}${button('New incident','new-incident','', 'btn small danger')}`;
  return `<div class="hero-strip">${practiceStateHero()}${demoControls()}</div>${banners}<div class="metrics">${metric(state.appointments.filter(a=>new Date(a.start).toDateString()===new Date().toDateString()).length,'Appointments today','Fictional demo','blue')}${metric(gaps.length,'Continuity flags','No diagnosis or risk score','amber')}${metric(open.length,'Open responsibilities',`${overdue.length} overdue`,'red')}${metric(checkOpen,'Safety checks open','Opening, midday and closing','gold')}${metric(supervisionDue.length,'Supervision items','Provisionals and supervisors','green')}${metric(state.incidents.filter(i=>i.status!=='closed').length,'Open incidents','Staff, privacy and safety','black')}</div>${sectionHeading('Today’s operational picture','The right person sees the right action, owner, due time and evidence gate.',dashboardActions)}<div class="grid main-side">${card('Priority queue','Unresolved work remains visible until an accountable outcome is recorded.',obligationRows(open.sort((a,b)=>Core.rank(b.level)-Core.rank(a.level)||new Date(a.dueAt)-new Date(b.dueAt))))}${card('Staff, coverage and wellbeing','A quick view of workload, leave, breaks and professional cover.',`<div class="list">${staffList}</div>`,button('Open staff board','go-page','data-page="staff"','btn small secondary'))}</div><div class="grid two" style="margin-top:14px">${card('Psychology-practice safety principles','Operating boundaries for the controlled demo.',`<div class="scoreless-safety"><div class="safety-step"><span>1</span><strong>Human judgement</strong><small>Authorised psychologists make clinical decisions.</small></div><div class="safety-step"><span>2</span><strong>No silent handovers</strong><small>Coverage is not complete until accepted.</small></div><div class="safety-step"><span>3</span><strong>No false closure</strong><small>A message sent is not an outcome.</small></div><div class="safety-step"><span>4</span><strong>Minimum access</strong><small>Reception sees only what is necessary.</small></div></div>`)}${card('Practice state explanation',`Current state: ${ps.level.toUpperCase()}`,`<div class="callout ${ps.level==='red'||ps.level==='black'?'danger':ps.level==='amber'?'warning':'success'}"><strong>${esc(ps.reason)}</strong>GENEVIEVE combines open responsibilities, incidents, safety checks, supervision, WHS hazards and insurance evidence. It does not calculate a clinical risk score.</div>`)}</div>`;
}

function renderDay(){
  const todays=state.appointments.filter(a=>new Date(a.start).toDateString()===new Date().toDateString()).sort((a,b)=>new Date(a.start)-new Date(b.start));
  const rows=todays.map(a=>{const c=clientById(a.clientId),s=staffById(a.clinicianId);return `<tr><td>${fmtTime(a.start)}</td><td><strong>${esc(c?.initials)}</strong><br><small>${esc(c?.code)}</small></td><td>${esc(s?.name||'Unassigned')}</td><td>${esc(a.mode)}</td><td>${levelPill(a.status==='coverage_required'?'red':a.status==='confirmed'?'green':'yellow',a.status.replaceAll('_',' '))}</td><td>${a.mode==='Telehealth'?(a.telehealthReady?levelPill('green','ready'):levelPill('amber','prep required')):'—'}</td><td>${!readOnly()?button('Update','appointment-status',`data-id="${a.id}"`,'btn small secondary'):''}</td></tr>`;}).join('');
  const my=state.obligations.filter(o=>o.status!=='closed'&&(o.ownerId===state.currentUserId||o.backupOwnerId===state.currentUserId));
  return `${sectionHeading('My day','Appointments, workload, breaks, telehealth preparation and owned follow-ups.',button('Create appointment task','new-obligation'))}<div class="grid main-side">${card('Today’s appointments','Fictional client codes only.',`<div class="table-wrap"><table class="data-table"><thead><tr><th>Time</th><th>Client</th><th>Psychologist</th><th>Mode</th><th>Status</th><th>Preparation</th><th></th></tr></thead><tbody>${rows}</tbody></table></div>`)}${card('My responsibilities','Items owned by the current demo user or held as backup.',obligationRows(my,10))}</div><div class="grid three" style="margin-top:14px">${card('Telehealth safety preparation','Completed before a remote session where required.',`<div class="kpi-line"><span>Identity verification plan</span>${levelPill('yellow','pending')}</div><div class="kpi-line"><span>Current location and emergency access</span>${levelPill('yellow','pending')}</div><div class="kpi-line"><span>Privacy and connection-failure plan</span>${levelPill('amber','required')}</div>`)}${card('Workload and breaks','Operational support, not performance surveillance.',state.staff.filter(s=>s.sessions>0).map(s=>`<div class="kpi-line"><span>${esc(s.name)} · ${s.sessions}/${s.maxSessions} sessions</span>${levelPill(s.breakStatus==='overdue'?'red':s.breakStatus==='due_soon'?'amber':'green',s.breakStatus.replaceAll('_',' '))}</div>`).join(''))}${card('End-of-session actions','Keep unfinished work visible without storing therapy notes.',`<div class="callout"><strong>Permitted in this demo</strong>Appointment outcome, next booking required, callback ownership, approved external correspondence, supervision prompt and staff debrief request.</div>`)}</div>`;
}

function renderStaff(){
  const rows=state.staff.map(s=>{const backup=staffById(s.backupId);return `<tr><td>${avatar(s,s.status==='leave'?'amber':s.breakStatus==='overdue'?'red':'green')}</td><td><strong>${esc(s.name)}</strong><br><small>${esc(s.role)}</small></td><td>${esc(s.registration)}<br><small>${esc(s.supervisorStatus)}</small></td><td>${esc(s.status.replaceAll('_',' '))}<br><small>${esc(s.availability.replaceAll('_',' '))}</small></td><td>${s.sessions}/${s.maxSessions||'—'}<br><small>high-support ${s.highSupport}/${s.maxHighSupport||'—'}</small></td><td>${levelPill(s.breakStatus==='overdue'?'red':s.breakStatus==='due_soon'?'amber':'green',s.breakStatus.replaceAll('_',' '))}</td><td>${esc(backup?.name||'Not assigned')}</td><td>${levelPill(s.piiStatus==='current'||s.piiStatus==='covered_by_business'?'green':'amber',s.piiStatus.replaceAll('_',' '))}</td><td>${button('Open','open-staff',`data-id="${s.id}"`,'btn small secondary')}</td></tr>`;}).join('');
  return `${sectionHeading('Staff safety, qualifications and coverage','Protect staff while maintaining continuity when somebody is sick, away, overloaded or working alone.',button('Record staff change','staff-change'))}<div class="grid two">${card('Coverage rules','Every affected appointment, callback, referral, report and safety obligation must be transferred to an eligible person who accepts it.',`<div class="callout warning"><strong>No silent coverage</strong>A name in a calendar is not enough. GENEVIEVE records offer, acceptance, declined work, workload limits, backup and return handover.</div>`)}${card('Capability and scope','Match work to registration, approved scope, modality experience and available supervision.',`<div class="module-grid"><div class="module-card"><span class="module-icon">◈</span><strong>Registration</strong><p>Verification date and status.</p></div><div class="module-card"><span class="module-icon">◇</span><strong>Scope</strong><p>Approved capabilities and limits.</p></div><div class="module-card"><span class="module-icon">♢</span><strong>Supervision</strong><p>Supervisor and backup access.</p></div><div class="module-card"><span class="module-icon">▣</span><strong>Insurance</strong><p>Current evidence and review date.</p></div></div>`)}</div>${card('Staff register','Fictional records demonstrate audit-ready operational fields.',`<div class="table-wrap"><table class="data-table"><thead><tr><th></th><th>Staff</th><th>Registration / supervision</th><th>Status</th><th>Load</th><th>Break</th><th>Backup</th><th>PII</th><th></th></tr></thead><tbody>${rows}</tbody></table></div>`,button('Export staff register','export-staff','', 'btn small secondary'))}<div class="grid three" style="margin-top:14px">${card('Psychosocial safety','Workload, emotional demands, aggression, vicarious trauma, bullying, fatigue and role conflict are visible as workplace risks.',`<div class="callout"><strong>Support before blame</strong>Alerts prompt a check-in, workload action, supervision, debrief or coverage review.</div>`)}${card('Lone and remote work','Remote and after-hours arrangements must have a contact, check-in and escalation pathway.',state.staff.filter(s=>s.loneWork).map(s=>`<div class="kpi-line"><span>${esc(s.name)}</span>${levelPill('amber','check-in required')}</div>`).join(''))}${card('Training due','Policies are not enough without staff understanding and competency evidence.',state.training.map(t=>`<div class="kpi-line"><span>${esc(t.title)}</span>${levelPill(t.status==='overdue'?'red':t.status==='due_soon'?'amber':'green',t.status.replaceAll('_',' '))}</div>`).join(''))}</div>`;
}

function renderSupervision(){
  const rows=state.supervision.map(s=>{const p=staffById(s.provisionalId),sup=staffById(s.supervisorId);const level=s.status==='overdue'?'red':Core.dueState(s.dueAt)==='due_soon'?'amber':s.status==='complete'?'green':'yellow';return `<div class="list-row">${avatar(p,level)}<div class="row-main"><strong>${esc(s.title)}</strong><small>Supervisor: ${esc(sup?.name)} · ${fmtDate(s.dueAt)} · ${esc(s.format)} · ${s.durationMinutes} minutes</small><div class="capability-tags">${s.focus.map(x=>`<span class="capability-tag">${esc(x)}</span>`).join('')}</div>${evidenceChips(s.requiredEvidence,s.evidence)}</div><div class="row-actions">${levelPill(level,s.status)}${button('Open','open-supervision',`data-id="${s.id}"`,'btn small secondary')}${!readOnly()&&allowed('participateSupervision')?button('Record','record-supervision',`data-id="${s.id}"`,'btn small'):''}</div></div>`;}).join('');
  const provisionals=state.staff.filter(s=>s.role.includes('Provisional')).map(s=>`<div class="policy-status"><div><strong>${esc(s.name)}</strong><small>${esc(s.registration)} · ${esc(s.supervisorStatus)}</small></div>${levelPill(s.supervisorStatus.includes('awaiting')?'amber':'green',s.supervisorStatus.includes('awaiting')?'action':'active')}</div>`).join('');
  return `${sectionHeading('Provisional psychologist supervision','Support new psychologists with clear scope, accessible supervisors, evidence and safe escalation.',button('Schedule supervision','new-supervision'))}<div class="grid two">${card('Supervision principles','The platform supports supervision governance but does not replace Board requirements or supervisor judgement.',`<div class="scoreless-safety"><div class="safety-step"><span>1</span><strong>Approved supervisor</strong><small>Named primary and backup.</small></div><div class="safety-step"><span>2</span><strong>Scope visible</strong><small>Work stays within approved capability.</small></div><div class="safety-step"><span>3</span><strong>Evidence recorded</strong><small>Attendance, actions and acknowledgement.</small></div><div class="safety-step"><span>4</span><strong>Escalation available</strong><small>Provisionals are never left without support.</small></div></div>`)}${card('Provisional governance status','A quick director and supervisor view.',provisionals)}</div>${card('Supervision schedule and evidence','Detailed client content belongs in the approved secure professional record, not this operational demo.',`<div class="list">${rows}</div>`,button('Export supervision register','export-supervision','', 'btn small secondary'))}<div class="grid three" style="margin-top:14px">${card('Competency and progression','Track agreed competency areas, observation, feedback and actions without reducing performance to one automated score.',`<div class="callout"><strong>Human assessment only</strong>GENEVIEVE organises evidence; the supervisor determines competency and progression.</div>`)}${card('Scope-of-practice gate','A provisional allocation can remain blocked until supervisor approval, insurance, competency and support evidence are current.',`<div class="warning-box">The system can prevent a workflow showing green when required supervision evidence is missing.</div>`)}${card('Supervisor capacity','A supervisor’s session load, high-support load, leave and debrief needs affect whether new responsibility should be offered.',state.staff.filter(s=>s.supervisorStatus.startsWith('Board')).map(s=>`<div class="kpi-line"><span>${esc(s.name)} · ${s.sessions}/${s.maxSessions} sessions</span>${levelPill(s.breakStatus==='overdue'?'red':'green',s.availability)}</div>`).join(''))}</div>`;
}

function renderContinuity(){
  const rows=state.clients.map(c=>{const level=Core.continuityState(c,state.obligations),primary=staffById(c.primaryClinicianId),backup=staffById(c.backupClinicianId);return `<tr><td>${levelPill(level)}</td><td><strong>${esc(c.initials)}</strong><br><small>${esc(c.code)} · ${esc(c.ageBand.replaceAll('_',' '))}</small></td><td>${esc(primary?.name)}<br><small>Backup: ${esc(backup?.name)}</small></td><td>${fmtDate(c.lastContact,false)}</td><td>${c.nextAppointment?fmtDate(c.nextAppointment):levelPill('amber','none booked')}</td><td>${esc(c.coverageStatus)}</td><td>${esc(c.consentStatus.replaceAll('_',' '))}</td><td>${button('Open','open-client',`data-id="${c.id}"`,'btn small secondary')}</td></tr>`;}).join('');
  return `${sectionHeading('Client continuity register','Administrative gaps stay visible until a responsible psychologist records the next action.',button('Create continuity task','new-obligation'))}<div class="callout warning" style="margin-bottom:14px"><strong>Safety boundary</strong>A missed appointment does not prove suicide risk. A lack of response does not prove safety. GENEVIEVE prompts the practice’s authorised procedure and records human decisions.</div>${card('Continuity overview','Fictional codes only. No therapy notes or diagnostic information.',`<div class="table-wrap"><table class="data-table"><thead><tr><th>State</th><th>Client</th><th>Psychologist</th><th>Last contact</th><th>Next appointment</th><th>Coverage</th><th>Consent</th><th></th></tr></thead><tbody>${rows}</tbody></table></div>`,button('Export continuity report','export-continuity','', 'btn small secondary'))}<div class="grid three" style="margin-top:14px">${card('What creates a flag','Approved operational rules, not diagnosis.',`<div class="kpi-line"><span>No next appointment</span>${levelPill('amber','attention')}</div><div class="kpi-line"><span>Cancellation without rebooking</span>${levelPill('amber','follow-up')}</div><div class="kpi-line"><span>Failed contact</span>${levelPill('amber','protocol')}</div><div class="kpi-line"><span>Unaccepted clinician coverage</span>${levelPill('red','urgent')}</div><div class="kpi-line"><span>Consent or safety-plan review due</span>${levelPill('amber','review')}</div>`)}${card('Inclusive access','Interpreter, accessibility, support-person and authorised-representative arrangements are shown before contact or attendance.',state.clients.filter(c=>c.accessibility!=='None recorded'||c.interpreter!=='Not required').map(c=>`<div class="kpi-line"><span>${esc(c.initials)} · ${esc(c.accessibility)}</span>${levelPill('blue',c.interpreter)}</div>`).join(''))}${card('Care transitions','External practitioner information, change of psychologist and authorised representatives receive explicit ownership.',state.clients.filter(c=>c.transition!=='none').map(c=>`<div class="kpi-line"><span>${esc(c.initials)} · ${esc(c.transition.replaceAll('_',' '))}</span>${levelPill(Core.continuityState(c,state.obligations))}</div>`).join(''))}</div>`;
}

function renderReception(){
  const rows=state.messages.filter(m=>m.status!=='closed').map(m=>{const owner=staffById(m.ownerId);return `<div class="list-row">${levelPill(m.level)}<div class="row-main"><strong>${esc(m.channel)} — ${esc(m.from)}</strong><small>${esc(m.summary)} · ${owner?`Owner: ${owner.name}`:'No owner'} · ${relativeDue(m.dueAt)}</small></div><div class="row-actions">${button('Open','open-message',`data-id="${m.id}"`,'btn small secondary')}${!readOnly()&&allowed('manageReception')?button('Close','close-message',`data-id="${m.id}"`,'btn small'):''}</div></div>`;}).join('');
  const scripts=[['Distressed caller','Stay calm, confirm immediate location only if the approved procedure requires it, and transfer to an available authorised psychologist. Reception does not assess risk.'],['Angry or threatening caller','Set a respectful boundary, end the interaction if unsafe, activate staff-safety procedures, preserve facts and notify the manager.'],['Psychologist absent','Use approved neutral wording, offer available arrangements, and do not disclose private staff information.'],['Message requested','Confirm identity and safe communication preference. Record the request, owner and due time; do not promise a clinical outcome.']];
  return `${sectionHeading('Reception support centre','Protect clients and reception staff with clear boundaries, minimal information and rapid escalation.',button('New message','new-message'))}<div class="grid main-side">${card('Live callback and message queue','Each item needs an owner, deadline and recorded outcome.',`<div class="list">${rows}</div>`)}${card('Reception boundary','Reception is never expected to make a clinical judgement.',`<div class="callout danger"><strong>Immediate concern</strong>Transfer to an authorised psychologist or approved emergency pathway. A message sent does not close a red concern.</div><div class="quick-grid" style="margin-top:10px"><button class="quick-action" data-action="immediate-concern"><span>!</span><div><strong>Immediate Safety Concern</strong><small>Open human-led workflow</small></div></button><button class="quick-action" data-action="new-incident"><span>⚑</span><div><strong>Staff safety incident</strong><small>Aggression, threat or injury</small></div></button></div>`)}</div>${card('Approved operational scripts','These are placeholders for Irene’s approved wording.',scripts.map(([name,text])=>`<div class="policy-status"><div><strong>${esc(name)}</strong><small>${esc(text)}</small></div>${button('Use','copy-script',`data-text="${esc(name)}"`,'btn small secondary')}</div>`).join(''))}<div class="grid three" style="margin-top:14px">${card('Safe communication','Before leaving a message, verify identity, permitted channel and whether details may be left.',`<div class="audit-ready">Permission visible before contact</div>`)}${card('Accessibility','Interpreter, mobility, communication and support-person needs are visible without exposing therapy content.',`<div class="audit-ready">Minimum necessary information</div>`)}${card('Reception wellbeing','Aggression, repeated distress calls, overload and traumatic exposure can create a staff check-in, break, debrief or incident.',`<div class="audit-ready">Staff support is part of safety</div>`)}</div>`;
}

function renderReferrals(){
  const rows=state.referrals.map(r=>{const reviewer=staffById(r.reviewerId);return `<tr><td>${levelPill(r.level)}</td><td><strong>${esc(r.code)}</strong><br><small>${esc(r.source)}</small></td><td>${fmtDate(r.receivedAt,false)}</td><td>${esc(r.status.replaceAll('_',' '))}</td><td>${esc(reviewer?.name||'Unassigned')}</td><td>${r.missingDocuments.length?`<span class="evidence-chip missing">${r.missingDocuments.length} missing</span>`:'Complete'}</td><td>${fmtDate(r.nextContact)}</td><td>${button('Open','open-referral',`data-id="${r.id}"`,'btn small secondary')}</td></tr>`;}).join('');
  return `${sectionHeading('Referrals, intake and waitlist safety','Every referral is received, evidence-checked, reviewed by an authorised person, allocated, redirected or closed.',button('New referral','new-referral'))}${card('Referral register','Stated urgency is recorded but the program does not make an autonomous clinical decision.',`<div class="table-wrap"><table class="data-table"><thead><tr><th>State</th><th>Referral</th><th>Received</th><th>Status</th><th>Reviewer</th><th>Evidence</th><th>Next contact</th><th></th></tr></thead><tbody>${rows}</tbody></table></div>`)}<div class="grid three" style="margin-top:14px">${card('Evidence gate','A referral cannot appear complete if required consent or contact evidence is missing.',`<div class="callout warning"><strong>No false green</strong>Missing evidence creates a visible obligation and due time.</div>`)}${card('Suitability and scope','Allocation considers practitioner scope, competence, registration, workload, supervision and service criteria.',`<div class="callout"><strong>Human review</strong>GENEVIEVE organises information; an authorised psychologist makes suitability decisions.</div>`)}${card('Waitlist continuity','Contact intervals, changed circumstances, decline/redirect outcomes and client communication remain owned.',`<div class="callout success"><strong>Every referral gets an outcome</strong>No referral should disappear in an inbox.</div>`)}</div>`;
}

function renderObligations(){
  let items=state.obligations.filter(o=>o.status!=='closed');if(ui.filter==='urgent')items=items.filter(o=>Core.rank(o.level)>=3);if(ui.filter==='overdue')items=items.filter(o=>Core.dueState(o.dueAt)==='overdue');if(ui.filter!=='all'&&!['urgent','overdue'].includes(ui.filter))items=items.filter(o=>o.category===ui.filter);if(ui.query)items=items.filter(o=>(o.title+' '+o.reason+' '+o.category).toLowerCase().includes(ui.query.toLowerCase()));items.sort((a,b)=>Core.rank(b.level)-Core.rank(a.level)||new Date(a.dueAt)-new Date(b.dueAt));
  const filters=`<div class="filter-bar"><div class="field"><label>Search</label><input data-search="obligations" value="${esc(ui.query)}" placeholder="Search responsibilities"></div><div class="field small-field"><label>Filter</label><select data-filter="obligations"><option value="all">All open</option><option value="urgent">Urgent</option><option value="overdue">Overdue</option><option value="care_continuity">Client continuity</option><option value="supervision">Supervision</option><option value="staff_safety">Staff safety</option><option value="safety">Immediate safety</option></select></div></div>`;
  return `${sectionHeading('Tasks, handovers and escalation','Detected → assigned → accepted → actioned → outcome recorded → reviewed → closed.',button('New task','new-obligation'))}${card('Responsibility queue','No ownerless work, silent handovers or closure without evidence.',filters+obligationRows(items,99),button('Run timed escalation','simulate-escalation','', 'btn small danger'))}`;
}

function renderSafety(){
  const incidentRows=state.incidents.map(i=>{const owner=staffById(i.ownerId);return `<div class="list-row">${levelPill(i.level)}<div class="row-main"><strong>${esc(i.title)}</strong><small>${esc(i.type)} · ${fmtDate(i.reportedAt)} · Owner: ${esc(owner?.name||'Unassigned')} · ${esc(i.status)}</small></div><div class="row-actions">${button('Open','open-incident',`data-id="${i.id}"`,'btn small secondary')}${i.status!=='closed'&&!readOnly()&&allowed('manageSafety')?button('Review','review-incident',`data-id="${i.id}"`,'btn small'):''}</div></div>`;}).join('');
  return `${sectionHeading('Safety and incident command','Support authorised response, staff safety, evidence and post-incident learning.',button('Immediate concern','immediate-concern','', 'btn small danger')+button('New incident','new-incident'))}<div class="grid two">${card('Immediate Safety Concern workflow','Human-led and policy-controlled.',`<div class="scoreless-safety"><div class="safety-step"><span>1</span><strong>Concern detected</strong><small>Facts and current contact context.</small></div><div class="safety-step"><span>2</span><strong>Psychologist assigned</strong><small>Acceptance is recorded.</small></div><div class="safety-step"><span>3</span><strong>Approved procedure</strong><small>Human decision and consultations.</small></div><div class="safety-step"><span>4</span><strong>Outcome and follow-up</strong><small>Review before closure.</small></div></div><div class="callout danger" style="margin-top:12px"><strong>The program must never</strong>Diagnose, calculate a suicide-risk score, declare safety, or automatically contact police, family or emergency contacts.</div>`)}${card('Staff safety after serious events','Psychologists, provisionals and reception staff may need immediate support, debrief, supervision, workload adjustment or time away.',`<div class="kpi-line"><span>Private debrief offered</span>${levelPill('amber','record outcome')}</div><div class="kpi-line"><span>Supervisor consultation</span>${levelPill('green','available')}</div><div class="kpi-line"><span>Work-related injury review</span>${levelPill('amber','manager action')}</div><div class="kpi-line"><span>Return-to-work support</span>${levelPill('yellow','if required')}</div>`)}</div>${card('Incident and near-miss register','Facts, immediate actions, people affected, evidence, review and learning.',`<div class="list">${incidentRows}</div>`,button('Export incident register','export-incidents','', 'btn small secondary'))}<div class="grid three" style="margin-top:14px">${card('Violence and aggression','Threatening calls, unsafe visitors, stalking concerns, abusive communication and physical risks.',`<div class="audit-ready">WHS hazard linked to incident</div>`)}${card('Privacy and cyber events','Wrong recipient, lost device, unauthorised access, disclosure or system compromise.',`<div class="audit-ready">Contain, assess, notify and learn</div>`)}${card('Mandatory notification decision support','A restricted record can preserve facts, consultation and authorised decisions without automating the decision.',`<div class="warning-box">Legal and professional notification decisions require qualified human review.</div>`)}</div>`;
}

function renderChecks(){
  const groups=state.checks.map(g=>{const complete=g.items.filter(i=>i.done).length;return `<div class="round-group"><div class="round-title"><h3>${esc(g.name)}</h3>${levelPill(complete===g.items.length?'green':'amber',`${complete}/${g.items.length} complete`)}</div>${g.items.map(i=>`<label class="check-row"><input type="checkbox" data-action="toggle-check" data-group="${g.id}" data-item="${i.id}" ${i.done?'checked':''} ${readOnly()?'disabled':''}><span><strong>${esc(i.title)}</strong><small>${i.done?`Completed ${fmtDate(i.doneAt)} by ${esc(staffById(i.doneBy)?.name||'demo user')}`:'Required evidence not yet recorded'}</small></span>${i.required?levelPill(i.done?'green':'amber',i.done?'complete':'required'):''}</label>`).join('')}</div>`;}).join('');
  return `${sectionHeading('Psychology practice safety checks','Short, practical checks that protect staff, clients, reception and continuity without creating clinical notes.',button('Complete next open check','complete-next-check'))}<div class="grid main-side">${card('Daily checks','Every completion is time-stamped in the evidence trail.',groups)}${card('What these checks cover','Designed specifically for a psychology practice.',`<div class="module-grid"><div class="module-card"><span class="module-icon">♙</span><strong>Coverage</strong><p>Leave, backup and supervision access.</p></div><div class="module-card"><span class="module-icon">☎</span><strong>Reception</strong><p>Phones, escalation and safe contact.</p></div><div class="module-card"><span class="module-icon">◷</span><strong>Workload</strong><p>Breaks, fatigue and lone work.</p></div><div class="module-card"><span class="module-icon">✓</span><strong>Closure</strong><p>Red items, callbacks and handovers.</p></div></div><div class="callout" style="margin-top:12px"><strong>Operational only</strong>These checks manage practice operations and worker/client safety. They do not assess or monitor a person’s mental state.</div>`)}</div>`;
}

function renderCompliance(){
  const hazardRows=state.whsHazards.map(h=>{const owner=staffById(h.ownerId);return `<tr><td>${levelPill(h.residualLevel)}</td><td><strong>${esc(h.hazard)}</strong><br><small>${esc(h.category)}</small></td><td>${esc(h.peopleExposed)}</td><td>${h.controls.map(c=>`<span class="capability-tag">${esc(c)}</span>`).join('')}</td><td>${esc(owner?.name)}</td><td>${fmtDate(h.reviewDue,false)}</td><td>${button('Review','review-hazard',`data-id="${h.id}"`,'btn small secondary')}</td></tr>`;}).join('');
  const injuryRows=state.workInjuries.map(w=>`<tr><td>${esc(w.workerCode)}</td><td>${esc(w.event)}</td><td>${fmtDate(w.occurredAt)}</td><td>${esc(w.workCoverStatus.replaceAll('_',' '))}<br><small>Reminder date: ${fmtDate(w.workCoverDueAt,false)}</small></td><td>${esc(w.consentToLodgeClaim.replaceAll('_',' '))}</td><td>${button('Open','open-work-injury',`data-id="${w.id}"`,'btn small secondary')}</td></tr>`).join('');
  const insuranceRows=state.insurance.map(i=>`<tr><td><strong>${esc(i.type)}</strong><br><small>${esc(i.holder)}</small></td><td>${esc(i.policyRef)}</td><td>${fmtDate(i.expiry,false)}</td><td>${levelPill(i.status==='current'?'green':'amber',i.status.replaceAll('_',' '))}</td><td>${esc(staffById(i.ownerId)?.name)}</td><td>${button('Verify','verify-insurance',`data-id="${i.id}"`,'btn small secondary')}</td></tr>`).join('');
  return `${sectionHeading('WHS, WorkCover and insurance evidence','A practical compliance register for management review and external audit preparation.',button('New WHS incident','new-incident')+button('Export compliance pack','export-compliance','', 'btn small secondary'))}<div class="grid two">${card('Audit-readiness status','Evidence is organised; final legal and insurance compliance must be confirmed by the practice and its advisers.',`<div class="kpi-line"><span>Workers compensation policy</span>${levelPill(state.insurance[0].status==='current'?'green':'red',state.insurance[0].status)}</div><div class="kpi-line"><span>Professional indemnity register</span>${levelPill('amber','review due')}</div><div class="kpi-line"><span>Psychosocial hazard register</span>${levelPill('green','active')}</div><div class="kpi-line"><span>Worker injury reporting workflow</span>${levelPill('amber','manager review')}</div><div class="kpi-line"><span>Incident and training evidence</span>${levelPill('green','available')}</div>`)}${card('WorkCover and worker privacy boundary','The demo records reporting dates, ownership and consent status, but not worker diagnosis or treatment details.',`<div class="callout warning"><strong>Manager reminder</strong>Report and claim processes are separate. A claim on behalf of a worker requires the proper consent and approved process. Exact deadlines and obligations must be verified for the real event.</div>`)}</div>${card('Psychosocial and workplace hazard register','Includes workload, emotional demands, aggression, remote work, confidentiality and other practice-specific hazards.',`<div class="table-wrap"><table class="data-table"><thead><tr><th>State</th><th>Hazard</th><th>People exposed</th><th>Controls</th><th>Owner</th><th>Review</th><th></th></tr></thead><tbody>${hazardRows}</tbody></table></div>`)}<div class="grid two" style="margin-top:14px">${card('Worker injury and reporting register','Fictional worker codes only.',`<div class="table-wrap"><table class="data-table"><thead><tr><th>Worker</th><th>Event</th><th>Date</th><th>WorkCover review</th><th>Claim consent</th><th></th></tr></thead><tbody>${injuryRows}</tbody></table></div>`,button('Record worker event','new-work-injury'))}${card('Insurance register','Workers compensation, PII, public liability, cyber and business continuity evidence.',`<div class="table-wrap"><table class="data-table"><thead><tr><th>Cover</th><th>Reference</th><th>Expiry</th><th>Status</th><th>Owner</th><th></th></tr></thead><tbody>${insuranceRows}</tbody></table></div>`)}</div>`;
}

function renderReports(){
  const timeline=state.audit.slice(0,30).map(a=>`<div class="timeline-item"><div class="audit-meta">${fmtDate(a.at)} · ${esc(staffById(a.actorId)?.name||'System')} · ${esc(a.category)}</div><strong>${esc(a.action)}</strong><small>${esc(a.detail)}</small></div>`).join('');
  const reports=[
    ['Daily command report','Practice state, open obligations, coverage, checks and incidents.','export-json'],
    ['Client continuity report','Fictional client codes, flags, ownership and next actions.','export-continuity'],
    ['Supervision register','Schedules, evidence gates, actions and progression status.','export-supervision'],
    ['Staff and credential register','Roles, registration prompts, scope, PII and training.','export-staff'],
    ['WHS and insurance pack','Hazards, controls, worker-event dates and policy evidence.','export-compliance'],
    ['Append-only audit CSV','Who saw, accepted, changed, escalated and completed work.','export-audit']
  ];
  return `${sectionHeading('Reports and evidence','Export fictional demo data for review without exporting therapy notes.',button('Print current view','print'))}<div class="grid main-side">${card('Report centre','Each report has a defined purpose and minimum data set.',reports.map(([name,desc,action])=>`<div class="policy-status"><div><strong>${esc(name)}</strong><small>${esc(desc)}</small></div>${button('Export',action,'','btn small secondary')}</div>`).join(''))}${card('Recent evidence timeline','The demonstration keeps a time-stamped activity record.',`<div class="timeline">${timeline}</div>`)}</div><div class="grid three" style="margin-top:14px">${card('Insurance evidence','Policy type, reference, expiry, verification, responsible owner and attached-evidence placeholder.',`<div class="audit-ready">Register fields prepared</div>`)}${card('WHS evidence','Hazard, affected workers, controls, owner, review date, residual state and linked incidents.',`<div class="audit-ready">Risk register prepared</div>`)}${card('Psychology governance evidence','Registration prompts, supervision, scope, professional conduct, consent, privacy and authorised review.',`<div class="audit-ready">Governance register prepared</div>`)}</div>`;
}

function renderGovernance(){
  const policies=state.policies.map(p=>`<div class="policy-status"><div><strong>${esc(p.title)}</strong><small>Version ${esc(p.version)} · owner ${esc(staffById(p.ownerId)?.name)} · review ${fmtDate(p.reviewDue,false)}</small></div>${levelPill(p.status.includes('required')?'amber':'yellow',p.status.replaceAll('_',' '))}</div>`).join('');
  const modules=[
    ['♙','Clinical workforce','Registration, role, scope, workload, leave and coverage.'],['◇','Provisional support','Supervisor access, agreements, competencies and evidence.'],['◎','Client continuity','No next appointment, failed contact, consent and accepted handover.'],['☎','Reception safety','Approved scripts, minimum access and urgent transfer.'],['!','Immediate safety','Human-led response, consultation, outcome and follow-up.'],['⚑','WHS and WorkCover','Psychosocial hazards, worker events, reporting and support.'],['▣','Insurance','Workers compensation, PII, liability, cyber and continuity.'],['▤','Evidence','Time-stamped audit, reports, policy versions and closure gates.']
  ];
  return `${sectionHeading('Governance and production readiness','This package is a working controlled demo. Production use requires approved policies, security, integrations and professional review.',button('Reset demo','reset-demo','', 'btn small danger'))}<div class="grid two">${card('Role and access model','Only the minimum operational information required for each role should be visible.',Object.entries(ROLE_BOUNDARIES).map(([r,text])=>`<div class="policy-status"><div><strong>${esc(ROLE_LABELS[r])}</strong><small>${esc(text)}</small></div>${levelPill(r===currentRole()?'green':'grey',r===currentRole()?'current':'configured')}</div>`).join(''))}${card('Escalation configuration','Timers and recipients must be approved by Mood & Mind Centre.',`<div class="kpi-line"><span>Red acknowledgement target</span><b>${state.settings.criticalAckMinutes} minutes</b></div><div class="kpi-line"><span>Amber acknowledgement target</span><b>${state.settings.highAckMinutes} minutes</b></div><div class="kpi-line"><span>Standard action target</span><b>${state.settings.normalAckMinutes} minutes</b></div><div class="kpi-line"><span>Chain</span><b>${esc(state.settings.escalationChain.join(' → '))}</b></div><div class="callout warning" style="margin-top:10px"><strong>Configuration only</strong>Real times and escalation recipients require Irene’s approval and testing.</div>`)}</div>${card('Policy approval register','Drafts are deliberately marked as requiring practice approval.',policies)}${card('Psychology safety platform coverage','Areas added for clients, psychologists, provisionals, reception, management and auditors.',`<div class="module-grid">${modules.map(([icon,name,desc])=>`<div class="module-card"><span class="module-icon">${icon}</span><strong>${esc(name)}</strong><p>${esc(desc)}</p></div>`).join('')}</div>`)}<div class="grid two" style="margin-top:14px">${card('Production blockers','Do not enter real identifiable information until these are complete.',`<div class="kpi-line"><span>Secure authentication and role permissions</span>${levelPill('red','not connected')}</div><div class="kpi-line"><span>Encrypted production database and backups</span>${levelPill('red','not connected')}</div><div class="kpi-line"><span>Privacy impact and cybersecurity review</span>${levelPill('amber','required')}</div><div class="kpi-line"><span>Clinical governance and emergency policy approval</span>${levelPill('amber','required')}</div><div class="kpi-line"><span>Practice-system integration and data migration</span>${levelPill('amber','required')}</div><div class="kpi-line"><span>User acceptance and emergency drills</span>${levelPill('amber','required')}</div>`)}${card('What is ready now','The controlled demonstration can be opened locally or deployed to a static host using fictional data.',`<div class="callout success"><strong>Working demonstration</strong>Navigation, role views, local fictional data, evidence gates, escalations, supervision, WHS, WorkCover reminders, insurance registers, reports, audit export and offline shell are operational.</div>`)}</div>`;
}

function openModal(title,subtitle,body,actions=''){document.getElementById('modalTitle').textContent=title;document.getElementById('modalSubtitle').textContent=subtitle||'';document.getElementById('modalBody').innerHTML=body;document.getElementById('modalActions').innerHTML=actions;document.getElementById('modalBackdrop').hidden=false;}
function closeModal(){document.getElementById('modalBackdrop').hidden=true;}
function field(label,id,value='',type='text',full=false,help=''){return `<div class="field ${full?'full':''}"><label for="${id}">${esc(label)}</label>${type==='textarea'?`<textarea id="${id}">${esc(value)}</textarea>`:type==='select'?value:`<input id="${id}" type="${type}" value="${esc(value)}">`}${help?`<span class="field-help">${esc(help)}</span>`:''}</div>`;}
function formValue(id){return document.getElementById(id)?.value?.trim()||'';}

function openObligation(id){const o=obligationById(id),owner=staffById(o.ownerId),backup=staffById(o.backupOwnerId);openModal(o.title,`${o.category.replaceAll('_',' ')} · ${o.level.toUpperCase()}`,detailList([['Reason',esc(o.reason)],['Owner',esc(owner?.name||'No accepted owner')],['Backup',esc(backup?.name||'Not assigned')],['Due',esc(fmtDate(o.dueAt))],['Policy',esc(o.policy)],['Outcome',esc(o.outcome||'Not recorded')]])+progress(o.stage)+`<h3>Evidence gate</h3>${evidenceChips(o.requiredEvidence,o.evidence)}`,`${!readOnly()?button('Add evidence','add-evidence',`data-id="${o.id}"`)+button('Advance','advance-obligation',`data-id="${o.id}"`)+button('Escalate','escalate-obligation',`data-id="${o.id}"`,'btn danger'):''}${button('Close','close-modal','','btn secondary')}`);}
function addEvidenceModal(id){const o=obligationById(id),missing=Core.missingEvidence(o);openModal('Add evidence',o.title,`<div class="form-grid">${field('Evidence type','evidenceType',missing[0]||'contact_outcome')}${field('Operational note','evidenceNote','', 'textarea',true,'Do not enter therapy content or identifiable information.')}</div>`,button('Save evidence','save-evidence',`data-id="${id}"`)+button('Cancel','close-modal','','btn secondary'));}
function saveEvidence(id){const o=obligationById(id),type=formValue('evidenceType'),note=formValue('evidenceNote');if(!type||!note)return toast('Evidence type and note are required');o.evidence.push({type,note,at:new Date().toISOString(),by:state.currentUserId});logAction('Evidence added',`${o.title}: ${type}.`,'evidence');closeModal();render();toast('Evidence saved');}
function advanceObligation(id){if(readOnly())return toast('Read-only role');const o=obligationById(id);if(!o.ownerId){o.ownerId=state.currentUserId;o.stage='accepted';logAction('Responsibility accepted',`${o.title} accepted by ${staffById(state.currentUserId)?.name}.`,'handover');closeModal();render();return toast('Responsibility accepted');}if(o.stage==='reviewed'){const missing=Core.missingEvidence(o);if(missing.length)return toast(`Cannot close — missing: ${missing.join(', ')}`);const outcome=prompt('Record the accountable outcome before closure',o.outcome||'');if(!outcome)return;o.outcome=outcome;o.stage='closed';o.status='closed';}else{o.stage=Core.nextStage(o.stage);if(o.stage==='outcome_recorded'&&!o.outcome){const outcome=prompt('Record outcome / next action');if(!outcome)return;o.outcome=outcome;}}logAction('Responsibility advanced',`${o.title} → ${o.stage}.`,'obligation');closeModal();render();toast(`Moved to ${o.stage.replaceAll('_',' ')}`);}
function escalateObligation(id){if(readOnly())return toast('Read-only role');const o=obligationById(id);o.escalationIndex=Math.min((o.escalationIndex||0)+1,state.settings.escalationChain.length-1);o.ownerId=o.escalationIndex===1?'s1':o.escalationIndex===2?'s1':o.ownerId;o.level=Core.rank(o.level)<3?'red':o.level;logAction('Responsibility escalated',`${o.title} escalated to ${state.settings.escalationChain[o.escalationIndex]}.`,'escalation');closeModal();render();toast('Escalation recorded');}
function runEscalationCheck(){let count=0;state.obligations.filter(o=>o.status!=='closed').forEach(o=>{if(Core.dueState(o.dueAt)==='overdue'||(Core.rank(o.level)>=3&&!o.ownerId)){o.level='red';o.escalationIndex=Math.min((o.escalationIndex||0)+1,state.settings.escalationChain.length-1);count++;}});logAction('Timed escalation check',`${count} item(s) escalated or retained as urgent.`,'escalation');render();toast(`${count} item(s) processed`);}

function openImmediateConcern(){if(readOnly())return toast('Read-only role');openModal('Immediate Safety Concern','Authorised human response only',`<div class="callout danger"><strong>Call 000 for an immediate emergency</strong>This workflow does not assess or score risk and does not automatically contact anybody.</div><div class="form-grid" style="margin-top:12px">${field('Fictional client code or context','concernContext','MMC-DEMO')}${field('Current contact channel','concernChannel','Phone')}${field('Facts observed or reported','concernFacts','', 'textarea',true,'Facts only. Do not include therapy notes or real personal details.')}${field('Assign authorised psychologist','concernOwner',`<select id="concernOwner"><option value="s1">Irene</option><option value="s2">Dr Avery</option></select>`,'select')}${field('Approved procedure','concernPolicy','Immediate Safety Concern procedure')}</div>`,button('Create red responsibility','save-safety-concern')+button('Cancel','close-modal','','btn secondary'));}
function saveSafetyConcern(){const facts=formValue('concernFacts');if(!facts)return toast('Facts are required');const owner=formValue('concernOwner')||'s1';const id=Core.uid('ob');state.obligations.unshift({id,title:`Immediate Safety Concern — ${formValue('concernContext')||'demo context'}`,category:'safety',clientId:null,level:'red',stage:'assigned',status:'open',ownerId:owner,backupOwnerId:'s1',createdAt:new Date().toISOString(),dueAt:isoOffset(10),requiredEvidence:['psychologist_acceptance','human_decision','contact_outcome','follow_up_plan'],evidence:[],outcome:'',escalationIndex:0,policy:formValue('concernPolicy'),reason:facts});logAction('Immediate Safety Concern opened',`Red responsibility assigned to ${staffById(owner)?.name}.`,'safety');closeModal();state.activePage='obligations';render();toast('Urgent responsibility created');}

function openIncidentForm(){if(readOnly())return toast('Read-only role');openModal('Record incident or near miss','Staff, client, privacy, security or business-continuity event',`<div class="form-grid">${field('Title','incidentTitle')}${field('Type','incidentType',`<select id="incidentType"><option>Violence or aggression</option><option>Worker injury or illness</option><option>Privacy or cyber event</option><option>Client safety event</option><option>Staff wellbeing event</option><option>Security or facility event</option><option>Near miss</option></select>`,'select')}${field('Operational level','incidentLevel',`<select id="incidentLevel"><option value="yellow">Yellow — learn</option><option value="amber" selected>Amber — follow-up</option><option value="red">Red — urgent</option><option value="black">Black — emergency pathway active</option></select>`,'select')}${field('Owner','incidentOwner',`<select id="incidentOwner">${state.staff.map(s=>`<option value="${s.id}">${esc(s.name)}</option>`).join('')}</select>`,'select')}${field('Facts','incidentFacts','', 'textarea',true,'Facts only; no therapy content or real worker medical details.')}${field('Immediate actions','incidentActions','', 'textarea',true)}</div>`,button('Save incident','save-incident')+button('Cancel','close-modal','','btn secondary'));}
function saveIncident(){const title=formValue('incidentTitle'),facts=formValue('incidentFacts');if(!title||!facts)return toast('Title and facts are required');state.incidents.unshift({id:Core.uid('inc'),title,type:formValue('incidentType'),level:formValue('incidentLevel'),status:'open',reportedAt:new Date().toISOString(),ownerId:formValue('incidentOwner'),peopleAffected:['Fictional demo'],facts,immediateActions:[formValue('incidentActions')||'Owner assigned'],followUp:['Manager review required'],evidence:['incident_record'],learning:'',workRelated:formValue('incidentType').includes('Worker')||formValue('incidentType').includes('Violence'),notifiableReview:'authorised_manager_review_required'});logAction('Incident recorded',title,'incident');closeModal();render();toast('Incident saved');}
function openIncident(id){const i=state.incidents.find(x=>x.id===id);openModal(i.title,`${i.type} · ${i.level.toUpperCase()}`,detailList([['Reported',esc(fmtDate(i.reportedAt))],['Owner',esc(staffById(i.ownerId)?.name||'Unassigned')],['Facts',esc(i.facts)],['Immediate actions',esc(i.immediateActions.join('; '))],['Follow-up',esc(i.followUp.join('; '))],['Notifiable review',esc(i.notifiableReview.replaceAll('_',' '))],['Learning',esc(i.learning||'Not yet recorded')]]),`${i.status!=='closed'&&!readOnly()&&allowed('manageSafety')?button('Review and close','review-incident',`data-id="${i.id}"`):''}${button('Close','close-modal','','btn secondary')}`);}
function reviewIncident(id){const i=state.incidents.find(x=>x.id===id),learning=prompt('Record manager/clinical review outcome and learning',i.learning||'');if(!learning)return;i.learning=learning;i.status='closed';i.evidence.push('manager_review','outcome_recorded');logAction('Incident reviewed and closed',`${i.title}: ${learning}`,'incident');closeModal();render();toast('Review recorded');}

function openStaff(id){const s=staffById(id),backup=staffById(s.backupId);openModal(s.name,s.role,detailList([['Registration',esc(s.registration)],['Supervisor status',esc(s.supervisorStatus)],['Status',esc(s.status.replaceAll('_',' '))],['Availability',esc(s.availability.replaceAll('_',' '))],['Sessions',`${s.sessions}/${s.maxSessions||'—'}`],['High-support load',`${s.highSupport}/${s.maxHighSupport||'—'}`],['Break',esc(s.breakStatus.replaceAll('_',' '))],['Backup',esc(backup?.name||'Not assigned')],['PII',`${esc(s.piiStatus.replaceAll('_',' '))} · review/expiry ${esc(fmtDate(s.piiExpiry,false))}`],['Lone work',s.loneWork?'Yes — check-in required':'No'],['Debrief preference',esc(s.debriefPreference)]])+`<h3>Capabilities</h3><div class="capability-tags">${s.capabilities.map(c=>`<span class="capability-tag">${esc(c)}</span>`).join('')}</div>`,`${!readOnly()&&allowed('manageWorkforce')?button('Update operational status','update-staff',`data-id="${s.id}"`)+button('Create coverage workflow','create-coverage',`data-id="${s.id}"`,'btn danger'):''}${button('Close','close-modal','','btn secondary')}`);}
function updateStaff(id){const s=staffById(id),status=prompt('Status: on_site, remote, leave, sick, unavailable',s.status);if(!['on_site','remote','leave','sick','unavailable'].includes(status))return;s.status=status;s.availability=['leave','sick','unavailable'].includes(status)?'unavailable':'available';logAction('Staff operational status changed',`${s.name}: ${status}.`,'workforce');closeModal();render();toast('Staff status updated');}
function createCoverage(id){const s=staffById(id),backup=staffById(s.backupId)||staffById('s1');const affected=state.clients.filter(c=>c.primaryClinicianId===id);affected.forEach(c=>{c.coverageStatus='unaccepted';state.obligations.unshift({id:Core.uid('ob'),title:`Accept coverage — ${c.initials}`,category:'care_continuity',clientId:c.id,level:'red',stage:'assigned',status:'open',ownerId:backup.id,backupOwnerId:'s1',createdAt:new Date().toISOString(),dueAt:isoOffset(30),requiredEvidence:['receiving_psychologist_acceptance','client_contact_outcome'],evidence:[],outcome:'',escalationIndex:0,policy:'Clinician absence and continuity procedure',reason:`${s.name} is unavailable; accepted coverage is required.`});});logAction('Coverage workflow created',`${affected.length} client obligation(s) offered to ${backup.name} for ${s.name}.`,'handover');closeModal();render();toast('Coverage responsibilities created');}
function staffChange(){if(readOnly())return toast('Read-only role');openModal('Record staff availability change','Use fictional details in this controlled demo',`<div class="form-grid">${field('Staff member','staffChangeId',`<select id="staffChangeId">${state.staff.map(s=>`<option value="${s.id}">${esc(s.name)} — ${esc(s.role)}</option>`).join('')}</select>`,'select')}${field('New status','staffChangeStatus',`<select id="staffChangeStatus"><option value="leave">Planned leave</option><option value="sick">Unexpected sickness</option><option value="unavailable">Emergency unavailable</option><option value="remote">Remote</option><option value="on_site">On site</option></select>`,'select')}${field('Operational reason','staffChangeReason','', 'textarea',true,'Do not enter private medical details.')}</div>`,button('Apply and identify dependencies','save-staff-change')+button('Cancel','close-modal','','btn secondary'));}
function saveStaffChange(){const id=formValue('staffChangeId'),s=staffById(id),status=formValue('staffChangeStatus');s.status=status;s.availability=['leave','sick','unavailable'].includes(status)?'unavailable':'available';logAction('Staff availability event',`${s.name}: ${status}. Reason: ${formValue('staffChangeReason')||'Not stated'}.`,'workforce');closeModal();if(s.availability==='unavailable')createCoverage(id);else render();}

function openClient(id){if(!allowed('viewClientOperational')&&currentRole()!=='director'&&currentRole()!=='reviewer')return toast('This role cannot open client operational details');const c=clientById(id),primary=staffById(c.primaryClinicianId),backup=staffById(c.backupClinicianId),level=Core.continuityState(c,state.obligations);openModal(`${c.initials} — ${c.code}`,`Operational continuity · ${level.toUpperCase()}`,detailList([['Primary psychologist',esc(primary?.name)],['Backup',esc(backup?.name)],['Last contact',esc(fmtDate(c.lastContact))],['Next appointment',esc(c.nextAppointment?fmtDate(c.nextAppointment):'None booked')],['Safe contact',esc(c.contactPreference)],['Message permitted',c.safeToLeaveMessage?'Yes — within recorded permission':'No detailed message'],['Consent status',esc(c.consentStatus.replaceAll('_',' '))],['Emergency contact permission',esc(c.emergencyContactPermission)],['Accessibility',esc(c.accessibility)],['Interpreter',esc(c.interpreter)],['Funding / plan review',esc(fmtDate(c.fundingExpiry,false))],['Coverage',esc(c.coverageStatus)],['Transition',esc(c.transition.replaceAll('_',' '))],['Operational note',esc(c.operationalNote)]])+`<div class="callout" style="margin-top:12px"><strong>Clinical content excluded</strong>Therapy notes, diagnosis, assessment results and treatment decisions remain in the approved clinical record.</div>`,`${!readOnly()?button('Create follow-up','client-followup',`data-id="${c.id}"`):''}${button('Close','close-modal','','btn secondary')}`);}
function clientFollowup(id){const c=clientById(id);state.obligations.unshift({id:Core.uid('ob'),title:`Continuity follow-up — ${c.initials}`,category:'care_continuity',clientId:c.id,level:'amber',stage:'assigned',status:'open',ownerId:c.primaryClinicianId,backupOwnerId:c.backupClinicianId,createdAt:new Date().toISOString(),dueAt:isoOffset(60),requiredEvidence:['contact_attempt','next_action'],evidence:[],outcome:'',escalationIndex:0,policy:'Client continuity procedure',reason:'Authorised user created an operational follow-up.'});logAction('Continuity follow-up created',c.code,'continuity');closeModal();state.activePage='obligations';render();toast('Follow-up created');}

function openMessage(id){const m=state.messages.find(x=>x.id===id),owner=staffById(m.ownerId);openModal(`${m.channel} — ${m.from}`,m.summary,detailList([['Owner',esc(owner?.name||'No owner')],['Due',esc(fmtDate(m.dueAt))],['State',esc(m.level.toUpperCase())],['Approved script',esc(m.safeScript)]]),`${!readOnly()&&allowed('manageReception')?button('Assign to me','assign-message',`data-id="${m.id}"`)+button('Close with outcome','close-message',`data-id="${m.id}"`):''}${button('Close','close-modal','','btn secondary')}`);}
function assignMessage(id){const m=state.messages.find(x=>x.id===id);m.ownerId=state.currentUserId;logAction('Message ownership accepted',`${m.channel} from ${m.from}.`,'reception');closeModal();render();toast('Message assigned');}
function closeMessage(id){const m=state.messages.find(x=>x.id===id),outcome=prompt('Record operational outcome / next action');if(!outcome)return;m.status='closed';logAction('Message closed',`${m.channel} from ${m.from}: ${outcome}`,'reception');closeModal();render();toast('Outcome recorded');}
function openMessageForm(){if(readOnly())return toast('Read-only role');openModal('New reception message','Fictional operational details only',`<div class="form-grid">${field('Channel','messageChannel',`<select id="messageChannel"><option>Phone</option><option>Voicemail</option><option>Email</option><option>Portal</option><option>In person</option></select>`,'select')}${field('From / code','messageFrom','Fictional enquiry')}${field('Summary','messageSummary','', 'textarea',true)}${field('Level','messageLevel',`<select id="messageLevel"><option value="yellow">Yellow</option><option value="amber" selected>Amber</option><option value="red">Red</option></select>`,'select')}</div>`,button('Save message','save-message')+button('Cancel','close-modal','','btn secondary'));}
function saveMessage(){const summary=formValue('messageSummary');if(!summary)return toast('Summary required');state.messages.unshift({id:Core.uid('m'),channel:formValue('messageChannel'),from:formValue('messageFrom'),summary,ownerId:null,dueAt:isoOffset(formValue('messageLevel')==='red'?10:60),level:formValue('messageLevel'),status:'open',safeScript:'Use the practice-approved minimum-information script and transfer concerns to an authorised psychologist.'});logAction('Reception message created',summary,'reception');closeModal();render();toast('Message saved');}

function openReferral(id){const r=state.referrals.find(x=>x.id===id);openModal(r.code,`${r.source} · ${r.status.replaceAll('_',' ')}`,detailList([['Received',esc(fmtDate(r.receivedAt))],['Reviewer',esc(staffById(r.reviewerId)?.name||'Unassigned')],['Documents',esc(r.documents.join(', ')||'None')],['Missing',esc(r.missingDocuments.join(', ')||'None')],['Next contact',esc(fmtDate(r.nextContact))],['Suitability decision',esc(r.suitabilityDecision.replaceAll('_',' '))]]),`${!readOnly()&&allowed('reviewReferral')?button('Add next missing evidence','referral-evidence',`data-id="${r.id}"`)+button('Advance','advance-referral',`data-id="${r.id}"`):''}${button('Close','close-modal','','btn secondary')}`);}
function referralEvidence(id){const r=state.referrals.find(x=>x.id===id);if(!r.missingDocuments.length)return toast('No missing evidence');const item=r.missingDocuments.shift();r.documents.push(item);if(!r.missingDocuments.length){r.status='clinical_review';r.level='yellow';}logAction('Referral evidence added',`${r.code}: ${item}.`,'referral');closeModal();render();toast('Evidence added');}
function advanceReferral(id){const r=state.referrals.find(x=>x.id===id);if(r.missingDocuments.length)return toast('Missing evidence blocks advancement');if(r.status==='clinical_review'){r.status='allocated';r.allocation=r.reviewerId;r.level='green';r.suitabilityDecision='authorised_reviewer_approved';}else if(r.status==='awaiting_evidence'){r.status='clinical_review';r.level='yellow';}else if(r.status==='waitlist'){r.nextContact=dateOffset(14);r.level='yellow';}logAction('Referral advanced',`${r.code}: ${r.status}.`,'referral');closeModal();render();toast('Referral updated');}
function openReferralForm(){if(readOnly())return toast('Read-only role');openModal('New referral','Fictional intake record',`<div class="form-grid">${field('Referral code','referralCode',`MMC-R${String(state.referrals.length+1).padStart(2,'0')}`)}${field('Source','referralSource','GP referral')}${field('Reviewer','referralReviewer',`<select id="referralReviewer">${state.staff.filter(s=>s.role.includes('Psychologist')).map(s=>`<option value="${s.id}">${esc(s.name)}</option>`).join('')}</select>`,'select')}${field('Missing evidence','referralMissing','consent, contact_preferences', 'text',true,'Comma-separated fictional evidence types.')}</div>`,button('Save referral','save-referral')+button('Cancel','close-modal','','btn secondary'));}
function saveReferral(){const code=formValue('referralCode');if(!code)return toast('Referral code required');const missing=formValue('referralMissing').split(',').map(x=>x.trim()).filter(Boolean);state.referrals.unshift({id:Core.uid('r'),code,source:formValue('referralSource'),receivedAt:new Date().toISOString(),status:missing.length?'awaiting_evidence':'clinical_review',level:missing.length?'amber':'yellow',reviewerId:formValue('referralReviewer'),documents:['referral'],missingDocuments:missing,allocation:null,nextContact:dateOffset(2),suitabilityDecision:'pending'});logAction('Referral received',code,'referral');closeModal();render();toast('Referral saved');}

function openSupervision(id){const s=state.supervision.find(x=>x.id===id),p=staffById(s.provisionalId),sup=staffById(s.supervisorId);openModal(s.title,`${s.format} · ${s.status}`,detailList([['Provisional',esc(p?.name)],['Supervisor',esc(sup?.name)],['Due',esc(fmtDate(s.dueAt))],['Duration',`${s.durationMinutes} minutes`],['Focus',esc(s.focus.join(', '))],['Progress',esc(s.competencyProgress)],['Actions',esc(s.actions.join('; ')||'None recorded')],['Record boundary',esc(s.privateNoteBoundary)]])+`<h3>Evidence</h3>${evidenceChips(s.requiredEvidence,s.evidence)}`,`${!readOnly()&&allowed('participateSupervision')?button('Record evidence','record-supervision',`data-id="${s.id}"`):''}${button('Close','close-modal','','btn secondary')}`);}
function recordSupervision(id){const s=state.supervision.find(x=>x.id===id),available=s.requiredEvidence.filter(type=>!s.evidence.some(e=>e.type===type));const type=prompt('Evidence type',available[0]||'actions');if(!type)return;const note=prompt('Operational supervision evidence / action (no client therapy content)');if(!note)return;s.evidence.push({type,note,at:new Date().toISOString(),by:state.currentUserId});if(Core.missingEvidence({requiredEvidence:s.requiredEvidence,evidence:s.evidence}).length===0)s.status='complete';logAction('Supervision evidence recorded',`${s.title}: ${type}.`,'supervision');closeModal();render();toast('Supervision record updated');}
function newSupervision(){if(!allowed('manageSupervision'))return toast('Supervisor or director role required');openModal('Schedule supervision','Fictional governance record',`<div class="form-grid">${field('Provisional','newSupProvisional',`<select id="newSupProvisional">${state.staff.filter(s=>s.role.includes('Provisional')).map(s=>`<option value="${s.id}">${esc(s.name)}</option>`).join('')}</select>`,'select')}${field('Supervisor','newSupSupervisor',`<select id="newSupSupervisor">${state.staff.filter(s=>s.supervisorStatus.startsWith('Board')).map(s=>`<option value="${s.id}">${esc(s.name)}</option>`).join('')}</select>`,'select')}${field('Focus','newSupFocus','scope, wellbeing, competency')}${field('Due date','newSupDue',new Date(Date.now()+7*86400000).toISOString().slice(0,10),'date')}</div>`,button('Schedule','save-supervision')+button('Cancel','close-modal','','btn secondary'));}
function saveSupervision(){const p=formValue('newSupProvisional'),sup=formValue('newSupSupervisor');state.supervision.unshift({id:Core.uid('sv'),title:`${staffById(p)?.name} — scheduled supervision`,provisionalId:p,supervisorId:sup,dueAt:new Date(formValue('newSupDue')+'T12:00:00').toISOString(),status:'scheduled',format:'Individual',durationMinutes:60,focus:formValue('newSupFocus').split(',').map(x=>x.trim()).filter(Boolean),requiredEvidence:['attendance','supervision_note','actions'],evidence:[],actions:[],competencyProgress:'To be reviewed by supervisor',privateNoteBoundary:'No therapy notes or identifiable client content in this operational record.'});logAction('Supervision scheduled',`${staffById(p)?.name} with ${staffById(sup)?.name}.`,'supervision');closeModal();render();toast('Supervision scheduled');}

function reviewHazard(id){if(!allowed('manageCompliance'))return toast('Director or clinical lead required');const h=state.whsHazards.find(x=>x.id===id),outcome=prompt('Record control review / additional action',h.controls.join('; '));if(!outcome)return;h.evidence.push(`review_${new Date().toISOString().slice(0,10)}`);h.reviewDue=dateOffset(30);if(confirm('Has residual risk reduced to yellow?'))h.residualLevel='yellow';logAction('WHS hazard reviewed',`${h.hazard}: ${outcome}`,'whs');render();toast('Hazard review recorded');}
function verifyInsurance(id){if(!allowed('manageCompliance'))return toast('Director or clinical lead required');const i=state.insurance.find(x=>x.id===id),note=prompt('Evidence checked / insurer or broker reference',i.policyRef);if(!note)return;i.status='current';i.evidence.push(`verified_${new Date().toISOString().slice(0,10)}`);logAction('Insurance evidence verified',`${i.type}: ${note}`,'insurance');render();toast('Insurance status verified');}
function openWorkInjury(id){const w=state.workInjuries.find(x=>x.id===id);openModal(`Worker event — ${w.workerCode}`,'Restricted operational reporting record',detailList([['Event',esc(w.event)],['Occurred',esc(fmtDate(w.occurredAt))],['Reported internally',esc(fmtDate(w.reportedInternallyAt))],['WorkCover review date',esc(fmtDate(w.workCoverDueAt))],['Status',esc(w.workCoverStatus.replaceAll('_',' '))],['Claim consent',esc(w.consentToLodgeClaim.replaceAll('_',' '))],['Manager',esc(staffById(w.managerOwnerId)?.name)],['Privacy boundary',esc(w.privacyNote)]]),`${!readOnly()&&allowed('manageCompliance')?button('Record reporting review','review-work-injury',`data-id="${w.id}"`):''}${button('Close','close-modal','','btn secondary')}`);}
function reviewWorkInjury(id){const w=state.workInjuries.find(x=>x.id===id),status=prompt('Status: review_required, reported, claim_discussed, closed',w.workCoverStatus);if(!['review_required','reported','claim_discussed','closed'].includes(status))return;w.workCoverStatus=status;if(status==='reported')w.evidence.push(`report_reference_${Date.now()}`);if(status==='closed')w.status='closed';logAction('Worker event reporting reviewed',`${w.workerCode}: ${status}.`,'workcover');closeModal();render();toast('Worker event updated');}
function newWorkInjury(){if(!allowed('manageCompliance'))return toast('Director or clinical lead required');openModal('Record work-related event','Do not enter diagnosis or private treatment details',`<div class="form-grid">${field('Worker code','workerCode','STAFF-DEMO')}${field('Event','workerEvent','', 'textarea',true)}${field('Internal report date','workerDate',new Date().toISOString().slice(0,10),'date')}${field('Manager','workerManager',`<select id="workerManager"><option value="s1">Irene</option><option value="s4">Priya</option></select>`,'select')}</div>`,button('Save restricted record','save-work-injury')+button('Cancel','close-modal','','btn secondary'));}
