function newObligation(){if(readOnly())return toast('Read-only role');openModal('New responsibility','Owner, due time and evidence are required',`<div class="form-grid">${field('Title','newObTitle')}${field('Category','newObCategory',`<select id="newObCategory"><option value="care_continuity">Client continuity</option><option value="supervision">Supervision</option><option value="staff_safety">Staff safety</option><option value="appointment">Appointment</option><option value="privacy">Privacy</option><option value="governance">Governance</option></select>`,'select')}${field('Level','newObLevel',`<select id="newObLevel"><option value="yellow">Yellow</option><option value="amber" selected>Amber</option><option value="red">Red</option></select>`,'select')}${field('Owner','newObOwner',`<select id="newObOwner"><option value="">Unassigned</option>${state.staff.map(s=>`<option value="${s.id}">${esc(s.name)}</option>`).join('')}</select>`,'select')}${field('Reason','newObReason','', 'textarea',true)}${field('Evidence required','newObEvidence','action_record, outcome_record', 'text',true,'Comma-separated evidence types.')}</div>`,button('Create responsibility','save-obligation')+button('Cancel','close-modal','','btn secondary'));}
function saveObligation(){const title=formValue('newObTitle');if(!title)return toast('Title required');const level=formValue('newObLevel'),owner=formValue('newObOwner');state.obligations.unshift({id:Core.uid('ob'),title,category:formValue('newObCategory'),clientId:null,level,stage:owner?'assigned':'detected',status:'open',ownerId:owner||null,backupOwnerId:'s1',createdAt:new Date().toISOString(),dueAt:isoOffset(level==='red'?10:level==='amber'?60:180),requiredEvidence:formValue('newObEvidence').split(',').map(x=>x.trim()).filter(Boolean),evidence:[],outcome:'',escalationIndex:0,policy:'Practice-approved procedure required',reason:formValue('newObReason')||'Operational responsibility created.'});logAction('Responsibility created',title,'obligation');closeModal();render();toast('Responsibility created');}

function appointmentStatus(id){const a=state.appointments.find(x=>x.id===id),choices=['confirmed','checked_in','in_progress','completed','cancelled','coverage_required','did_not_attend'];const next=prompt(`Enter status: ${choices.join(', ')}`,a.status);if(!choices.includes(next))return;a.status=next;if(next==='did_not_attend'){const c=clientById(a.clientId);state.obligations.unshift({id:Core.uid('ob'),title:`Non-attendance follow-up — ${c.initials}`,category:'care_continuity',clientId:c.id,level:'amber',stage:'assigned',status:'open',ownerId:a.clinicianId,backupOwnerId:c.backupClinicianId,createdAt:new Date().toISOString(),dueAt:isoOffset(60),requiredEvidence:['contact_attempt','approved_protocol','next_action'],evidence:[],outcome:'',escalationIndex:0,policy:'Non-attendance and failed-contact procedure',reason:'Appointment recorded as did not attend. This is not an automated risk conclusion.'});}logAction('Appointment status updated',`${clientById(a.clientId)?.initials}: ${next}.`,'appointment');render();toast('Appointment updated');}
function toggleCheck(groupId,itemId,checked){if(readOnly())return;const g=state.checks.find(x=>x.id===groupId),item=g.items.find(x=>x.id===itemId);item.done=checked;item.doneAt=checked?new Date().toISOString():null;item.doneBy=checked?state.currentUserId:null;logAction(checked?'Safety check completed':'Safety check reopened',`${g.name}: ${item.title}.`,'safety_check');render();toast(checked?'Check completed':'Check reopened');}
function completeNextCheck(){for(const g of state.checks){const item=g.items.find(i=>!i.done);if(item){toggleCheck(g.id,item.id,true);return;}}toast('All safety checks complete');}

function downloadFile(filename,text,type='application/json'){const blob=new Blob([text],{type});const url=URL.createObjectURL(blob);const a=document.createElement('a');a.href=url;a.download=filename;a.click();setTimeout(()=>URL.revokeObjectURL(url),1000);}
function exportJson(){logAction('Demo dataset exported','Full fictional operational dataset exported.','export');downloadFile('mood-mind-genevieve-psychology-demo.json',JSON.stringify(state,null,2));toast('Demo JSON exported');}
function exportAudit(){if(!allowed('exportAudit'))return toast('Director or clinical lead required');const head=['timestamp','actor','category','action','detail'];const rows=state.audit.map(a=>[a.at,staffById(a.actorId)?.name||'System',a.category,a.action,a.detail].map(v=>`"${String(v).replaceAll('"','""')}"`).join(','));downloadFile('mood-mind-audit-trail.csv',[head.join(','),...rows].join('\n'),'text/csv');toast('Audit CSV exported');}
function exportContinuity(){const data=state.clients.map(c=>({code:c.code,state:Core.continuityState(c,state.obligations),primary:staffById(c.primaryClinicianId)?.name,backup:staffById(c.backupClinicianId)?.name,lastContact:c.lastContact,nextAppointment:c.nextAppointment,coverage:c.coverageStatus,consent:c.consentStatus,accessibility:c.accessibility,transition:c.transition,openObligations:state.obligations.filter(o=>o.clientId===c.id&&o.status!=='closed').map(o=>o.title)}));downloadFile('mood-mind-client-continuity-fictional.json',JSON.stringify(data,null,2));toast('Continuity report exported');}
function exportSupervision(){downloadFile('mood-mind-supervision-register-fictional.json',JSON.stringify(state.supervision,null,2));toast('Supervision register exported');}
function exportStaff(){const data=state.staff.map(({id,name,role,registration,supervisorStatus,piiStatus,piiExpiry,status,availability,sessions,maxSessions,highSupport,maxHighSupport,breakStatus,backupId,loneWork,trainingDue,capabilities})=>({id,name,role,registration,supervisorStatus,piiStatus,piiExpiry,status,availability,sessions,maxSessions,highSupport,maxHighSupport,breakStatus,backup:staffById(backupId)?.name,loneWork,trainingDue,capabilities}));downloadFile('mood-mind-staff-and-credential-register-fictional.json',JSON.stringify(data,null,2));toast('Staff register exported');}
function exportIncidents(){downloadFile('mood-mind-incident-register-fictional.json',JSON.stringify(state.incidents,null,2));toast('Incident register exported');}
function exportCompliance(){const pack={generatedAt:new Date().toISOString(),notice:'Fictional controlled demo. Verify all legal, insurer and practice requirements before production use.',whsHazards:state.whsHazards,workInjuries:state.workInjuries,insurance:state.insurance,training:state.training,policies:state.policies,incidents:state.incidents.filter(i=>i.workRelated)};downloadFile('mood-mind-whs-workcover-insurance-demo-pack.json',JSON.stringify(pack,null,2));toast('Compliance demo pack exported');}
function resetDemo(){if(!confirm('Reset all fictional demo changes?'))return;state=createInitialState();saveState();render();toast('Demo reset');}

function scenario(name){if(readOnly())return toast('Read-only role');if(name==='staff_absence'){const s=staffById('s2');s.status='sick';s.availability='unavailable';createCoverage('s2');return;}if(name==='distressed_call'){state.messages.unshift({id:Core.uid('m'),channel:'Phone',from:'Fictional caller',summary:'Distressed caller requests urgent psychologist contact',ownerId:null,dueAt:isoOffset(5),level:'red',status:'open',safeScript:'Transfer immediately to an available authorised psychologist. Reception does not assess risk.'});state.obligations.unshift({id:Core.uid('ob'),title:'Immediate response to distressed caller',category:'safety',clientId:null,level:'red',stage:'detected',status:'open',ownerId:null,backupOwnerId:'s1',createdAt:new Date().toISOString(),dueAt:isoOffset(5),requiredEvidence:['psychologist_acceptance','human_decision','contact_outcome','follow_up_plan'],evidence:[],outcome:'',escalationIndex:0,policy:'Immediate Safety Concern procedure',reason:'Reception requested immediate transfer.'});logAction('Demo scenario started','Distressed-caller response added.','scenario');state.activePage='dashboard';render();toast('Distressed-caller scenario loaded');return;}if(name==='provisional_gap'){const sv=state.supervision.find(x=>x.id==='sv2');sv.status='overdue';sv.dueAt=isoOffset(-120);const o=obligationById('o4');o.level='red';o.dueAt=isoOffset(-30);logAction('Demo scenario started','Provisional supervision and scope evidence overdue.','scenario');state.activePage='supervision';render();toast('Supervision-gap scenario loaded');return;}if(name==='workplace_incident'){state.incidents.unshift({id:Core.uid('inc'),title:'Fictional staff member threatened by visitor',type:'Violence or aggression',level:'red',status:'open',reportedAt:new Date().toISOString(),ownerId:'s1',peopleAffected:['Fictional staff'],facts:'Threatening behaviour reported at reception. No identifiable details.',immediateActions:['Duress response activated','Staff moved to safe area','Manager notified'],followUp:['Notifiable incident review','Worker support','Control review'],evidence:['incident_record'],learning:'',workRelated:true,notifiableReview:'urgent_authorised_review_required'});logAction('Demo scenario started','Workplace violence scenario added.','scenario');state.activePage='compliance';render();toast('WHS incident scenario loaded');}}

function handleAction(action,el){
  if(action==='close-modal')return closeModal();if(action==='print')return window.print();if(action==='go-page'){state.activePage=el.dataset.page;return render();}if(action==='urgent-queue'){ui.filter='urgent';state.activePage='obligations';return render();}
  if(action==='new-obligation')return newObligation();if(action==='save-obligation')return saveObligation();if(action==='open-obligation')return openObligation(el.dataset.id);if(action==='add-evidence')return addEvidenceModal(el.dataset.id);if(action==='save-evidence')return saveEvidence(el.dataset.id);if(action==='advance-obligation')return advanceObligation(el.dataset.id);if(action==='escalate-obligation')return escalateObligation(el.dataset.id);if(action==='simulate-escalation')return runEscalationCheck();
  if(action==='immediate-concern')return openImmediateConcern();if(action==='save-safety-concern')return saveSafetyConcern();if(action==='new-incident')return openIncidentForm();if(action==='save-incident')return saveIncident();if(action==='open-incident')return openIncident(el.dataset.id);if(action==='review-incident')return reviewIncident(el.dataset.id);
  if(action==='open-staff')return openStaff(el.dataset.id);if(action==='update-staff')return updateStaff(el.dataset.id);if(action==='create-coverage')return createCoverage(el.dataset.id);if(action==='staff-change')return staffChange();if(action==='save-staff-change')return saveStaffChange();
  if(action==='open-client')return openClient(el.dataset.id);if(action==='client-followup')return clientFollowup(el.dataset.id);
  if(action==='open-message')return openMessage(el.dataset.id);if(action==='assign-message')return assignMessage(el.dataset.id);if(action==='close-message')return closeMessage(el.dataset.id);if(action==='new-message')return openMessageForm();if(action==='save-message')return saveMessage();if(action==='copy-script')return toast(`Approved placeholder selected: ${el.dataset.text}`);
  if(action==='open-referral')return openReferral(el.dataset.id);if(action==='referral-evidence')return referralEvidence(el.dataset.id);if(action==='advance-referral')return advanceReferral(el.dataset.id);if(action==='new-referral')return openReferralForm();if(action==='save-referral')return saveReferral();
  if(action==='open-supervision')return openSupervision(el.dataset.id);if(action==='record-supervision')return recordSupervision(el.dataset.id);if(action==='new-supervision')return newSupervision();if(action==='save-supervision')return saveSupervision();
  if(action==='review-hazard')return reviewHazard(el.dataset.id);if(action==='verify-insurance')return verifyInsurance(el.dataset.id);if(action==='open-work-injury')return openWorkInjury(el.dataset.id);if(action==='review-work-injury')return reviewWorkInjury(el.dataset.id);if(action==='new-work-injury')return newWorkInjury();if(action==='save-work-injury')return saveWorkInjury();
  if(action==='appointment-status')return appointmentStatus(el.dataset.id);if(action==='complete-next-check')return completeNextCheck();
  if(action==='export-json')return exportJson();if(action==='export-audit')return exportAudit();if(action==='export-continuity')return exportContinuity();if(action==='export-supervision')return exportSupervision();if(action==='export-staff')return exportStaff();if(action==='export-incidents')return exportIncidents();if(action==='export-compliance')return exportCompliance();if(action==='reset-demo')return resetDemo();
}

document.addEventListener('click',event=>{const nav=event.target.closest('[data-nav]');if(nav){state.activePage=nav.dataset.nav;document.getElementById('sidebar').classList.remove('open');render();return;}const sc=event.target.closest('[data-scenario]');if(sc){scenario(sc.dataset.scenario);return;}const action=event.target.closest('[data-action]');if(action){handleAction(action.dataset.action,action);return;}if(event.target.id==='modalBackdrop')closeModal();});
document.addEventListener('change',event=>{if(event.target.id==='roleSelect'){state.role=event.target.value;state.currentUserId=state.role==='reception'?'s4':state.role==='psychologist'?'s2':state.role==='provisional'?'s6':'s1';logAction('Demo role changed',`View changed to ${ROLE_LABELS[state.role]}.`,'access');render();}if(event.target.matches('[data-filter="obligations"]')){ui.filter=event.target.value;render();}if(event.target.matches('[data-action="toggle-check"]'))toggleCheck(event.target.dataset.group,event.target.dataset.item,event.target.checked);});
document.addEventListener('input',event=>{if(event.target.matches('[data-search="obligations"]')){ui.query=event.target.value;clearTimeout(ui.searchTimer);ui.searchTimer=setTimeout(render,180);}});
document.addEventListener('keydown',event=>{if(event.key==='Escape'&&!document.getElementById('modalBackdrop').hidden)closeModal();});
document.getElementById('menuButton').addEventListener('click',()=>document.getElementById('sidebar').classList.toggle('open'));
document.getElementById('modalClose').addEventListener('click',closeModal);
document.getElementById('urgentButton').addEventListener('click',openImmediateConcern);
document.getElementById('notificationButton').addEventListener('click',()=>{ui.filter='urgent';state.activePage='obligations';render();});
document.getElementById('dismissDemoNotice').addEventListener('click',()=>{try{sessionStorage.setItem(SESSION_KEY,'1');}catch(e){}document.getElementById('demoNotice').classList.add('dismissed');});
try{if(sessionStorage.getItem(SESSION_KEY)==='1')document.getElementById('demoNotice').classList.add('dismissed');}catch(e){}
const detailStyle=document.createElement('style');detailStyle.textContent='.detail-list{display:grid;grid-template-columns:170px minmax(0,1fr);gap:8px 12px;font-size:.76rem}.detail-list dt{font-weight:800;color:var(--muted)}.detail-list dd{margin:0;color:var(--ink)}.modal h3{font-size:.82rem;color:var(--navy);margin:16px 0 8px}@media(max-width:560px){.detail-list{grid-template-columns:1fr;gap:3px}.detail-list dd{margin-bottom:8px}}';document.head.appendChild(detailStyle);
updateClock();setInterval(updateClock,1000);render();
if('serviceWorker' in navigator&&location.protocol.startsWith('http'))navigator.serviceWorker.register('sw.js').catch(()=>{});
